----------------------------
---- DYNAMIC BORDER SIZE ----
----------------------------

local function update_border()
	local ws = hl.get_active_workspace()
	if not ws then
		return
	end

	if ws.windows >= 2 then
		hl.config({ general = { border_size = 2 } })
	else
		hl.config({ general = { border_size = 0 } })
	end
end

hl.on("window.active", update_border)
hl.on("window.open", update_border)
hl.on("window.close", update_border)
hl.on("workspace.active", update_border)

